import React, { useEffect, useRef, useState } from "react";
import "./Experience.css";

const EXPERIENCES = [
  {
    id: 1,
    index: 0,
    name: "Sanjay Arora",
    company: "Shells Advertising Inc.",
    website: "https://shellsindia.com",
    websiteLabel: "shellsindia.com",
    period: "May 2025 - Present",
    tag: "CURRENT",
    role: "Senior Video Editor",
    type: "Advertising Agency - Nagpur, India",
    color: "#4361ee",
    description:
      "Creating campaign videos and brand stories for one of central India's largest advertising agencies. Clients include Haldiram's, DM IMS, Spacewood and more.",
    stats: [
      { value: "12+", label: "Brand Clients" },
      { value: "34+", label: "Years Agency" },
    ],
  },
  {
    id: 2,
    index: 1,
    name: "Sneha Taori",
    company: "Personal Brand",
    website: "https://snehataori.com",
    websiteLabel: "snehataori.com",
    period: "Aug 2024 - Apr 2025",
    tag: "PREV",
    role: "Senior Video Editor",
    type: "Content Creator - India",
    color: "#f72585",
    description:
      "Crafted high-retention video content for a personal brand. Built a signature visual language through precise cuts and cinematic colour grading - drove consistent audience growth.",
    stats: [
      { value: "50+", label: "Videos Edited" },
      { value: "3x", label: "Engagement" },
    ],
  },
  {
    id: 3,
    index: 2,
    name: "Freelance Projects",
    company: "Independent",
    website: null,
    websiteLabel: null,
    period: "Sept 2023 - Jul 2024",
    tag: "FREELANCE",
    role: "Video Editor",
    type: "Freelance - Remote",
    color: "#7b5ea7",
    description:
      "Worked with multiple independent clients across YouTube, social media and short-film production. Developed versatile editing skills across formats, styles and genres.",
    stats: [
      { value: "10+", label: "Clients" },
      { value: "2+", label: "Years Exp." },
    ],
  },
];

function hexToRgb(hex) {
  const clean = hex.replace("#", "");
  const parsed = parseInt(clean, 16);
  const r = (parsed >> 16) & 255;
  const g = (parsed >> 8) & 255;
  const b = parsed & 255;
  return `${r}, ${g}, ${b}`;
}

function buildPath(from, to) {
  const dx = to.x - from.x;
  const dy = to.y - from.y;
  const cp1 = { x: from.x + dx * 0.1, y: from.y + dy * 0.6 };
  const cp2 = { x: to.x - dx * 0.1, y: to.y - dy * 0.6 };
  return `M ${from.x} ${from.y} C ${cp1.x} ${cp1.y}, ${cp2.x} ${cp2.y}, ${to.x} ${to.y}`;
}

export default function Experience() {
  const svgContainerRef = useRef(null);
  const dotRefs = useRef([]);
  const pathRefs = useRef([]);
  const drawTimeoutsRef = useRef([]);
  const calcTimeoutRef = useRef(null);
  const [dots, setDots] = useState([]);
  const [paths, setPaths] = useState([]);

  useEffect(() => {
    const compute = () => {
      const container = svgContainerRef.current;
      if (!container || dotRefs.current.length < 3) return;
      const containerRect = container.getBoundingClientRect();
      const dotPoints = dotRefs.current.map((el) => {
        if (!el) return { x: 0, y: 0 };
        const r = el.getBoundingClientRect();
        return {
          x: r.left + r.width / 2 - containerRect.left,
          y: r.top + r.height / 2 - containerRect.top,
        };
      });
      if (dotPoints.some((p) => p.x === 0 && p.y === 0)) return;
      setDots(dotPoints);
      setPaths([buildPath(dotPoints[0], dotPoints[1]), buildPath(dotPoints[1], dotPoints[2])]);
    };

    calcTimeoutRef.current = setTimeout(compute, 50);

    const ro = new ResizeObserver(() => {
      compute();
    });
    if (svgContainerRef.current) {
      ro.observe(svgContainerRef.current);
    }

    window.addEventListener("resize", compute);
    return () => {
      clearTimeout(calcTimeoutRef.current);
      window.removeEventListener("resize", compute);
      ro.disconnect();
    };
  }, []);

  useEffect(() => {
    drawTimeoutsRef.current.forEach((t) => clearTimeout(t));
    drawTimeoutsRef.current = [];

    paths.forEach((_, i) => {
      const el = pathRefs.current[i];
      if (!el) return;
      const len = el.getTotalLength();
      el.style.transition = "none";
      el.style.strokeDasharray = `${len}`;
      el.style.strokeDashoffset = `${len}`;
      const delay = i === 0 ? 1400 : 3000;
      const timeout = setTimeout(() => {
        el.style.transition = `stroke-dashoffset ${i === 0 ? 1.2 : 1.0}s cubic-bezier(0.4,0,0.2,1)`;
        el.style.strokeDashoffset = "0";
      }, delay);
      drawTimeoutsRef.current.push(timeout);
    });

    return () => {
      drawTimeoutsRef.current.forEach((t) => clearTimeout(t));
      drawTimeoutsRef.current = [];
    };
  }, [paths]);

  return (
    <section className="experience-page">
      <h1 className="experience-heading">Experience</h1>

      <div ref={svgContainerRef} className="experience-spread-container">
        <svg className="experience-svg" aria-hidden="true">
          {dots.length === 3 && (
            <defs>
              <linearGradient
                id="line-grad-1"
                gradientUnits="userSpaceOnUse"
                x1={dots[0].x}
                y1={dots[0].y}
                x2={dots[1].x}
                y2={dots[1].y}
              >
                <stop offset="0%" stopColor="#4361ee" stopOpacity="0" />
                <stop offset="15%" stopColor="#4361ee" stopOpacity="0.5" />
                <stop offset="85%" stopColor="#f72585" stopOpacity="0.5" />
                <stop offset="100%" stopColor="#f72585" stopOpacity="0" />
              </linearGradient>
              <linearGradient
                id="line-grad-2"
                gradientUnits="userSpaceOnUse"
                x1={dots[1].x}
                y1={dots[1].y}
                x2={dots[2].x}
                y2={dots[2].y}
              >
                <stop offset="0%" stopColor="#f72585" stopOpacity="0" />
                <stop offset="15%" stopColor="#f72585" stopOpacity="0.4" />
                <stop offset="85%" stopColor="#7b5ea7" stopOpacity="0.4" />
                <stop offset="100%" stopColor="#7b5ea7" stopOpacity="0" />
              </linearGradient>
              <filter id="line-glow">
                <feGaussianBlur stdDeviation="2" result="blur" />
                <feMerge>
                  <feMergeNode in="blur" />
                  <feMergeNode in="SourceGraphic" />
                </feMerge>
              </filter>
            </defs>
          )}

          {paths.map((d, i) => (
            <g key={`path-${i}`}>
              <path
                d={d}
                stroke={`url(#line-grad-${i + 1})`}
                strokeWidth="6"
                fill="none"
                filter="url(#line-glow)"
                opacity="0.3"
              />
              <path
                ref={(el) => {
                  pathRefs.current[i] = el;
                }}
                d={d}
                stroke={`url(#line-grad-${i + 1})`}
                strokeWidth="1"
                fill="none"
                opacity="0.7"
              />
            </g>
          ))}
        </svg>

        <div className="experience-nodes">
          {EXPERIENCES.map((exp, idx) => {
            const isEven = idx % 2 === 0;
            return (
              <React.Fragment key={exp.id}>
                <div className={`experience-node-row ${isEven ? "is-even" : "is-odd"} node-${idx + 1}`}>
                  <div className={`info-block node-${idx + 1}-info`}>
                    <div className={`name-line reveal node-${idx + 1}-name`}>
                      <h2>{exp.name}</h2>
                      <span className={`tag-pill tag-${exp.tag.toLowerCase()}`}>
                        {exp.tag === "CURRENT" && <span className="tag-live-dot" aria-hidden="true" />}
                        {exp.tag}
                      </span>
                    </div>

                    <div className={`role-type-line reveal node-${idx + 1}-role`}>
                      <span className="role-text" style={{ color: exp.color }}>
                        {exp.role}
                      </span>
                      <span className="dot-sep">·</span>
                      <span>{exp.type}</span>
                    </div>

                    <div className={`period-line reveal node-${idx + 1}-period`}>
                      <span className="period-bar" aria-hidden="true" />
                      <span>{exp.period}</span>
                    </div>

                    <p className={`description reveal node-${idx + 1}-description`}>{exp.description}</p>

                    <div className={`stats-row reveal node-${idx + 1}-stats`}>
                      {exp.stats.map((stat) => (
                        <div key={stat.label} className="stat-item">
                          <span className="stat-value" style={{ color: exp.color }}>
                            {stat.value}
                          </span>
                          <span className="stat-label">{stat.label}</span>
                        </div>
                      ))}
                    </div>

                    {exp.website && (
                      <a
                        className={`website-link reveal node-${idx + 1}-website`}
                        href={exp.website}
                        target="_blank"
                        rel="noreferrer"
                      >
                        <span>{exp.websiteLabel}</span>
                        <svg viewBox="0 0 10 10" width="9" height="9" aria-hidden="true">
                          <path d="M1 9L9 1M9 1H3M9 1v6" />
                        </svg>
                      </a>
                    )}
                  </div>

                  <div className={`dot-block reveal node-${idx + 1}-dot`}>
                    <span
                      ref={(el) => {
                        dotRefs.current[idx] = el;
                      }}
                      className={`node-dot node-dot-${idx + 1}`}
                      style={{
                        "--accent": exp.color,
                        "--accent-rgb": hexToRgb(exp.color),
                      }}
                    />
                    <span className="mobile-dot-period">{exp.period}</span>
                  </div>
                </div>

                {idx < EXPERIENCES.length - 1 && <div className="node-divider" aria-hidden="true" />}
                {idx < EXPERIENCES.length - 1 && <div className="mobile-connector" aria-hidden="true" />}
              </React.Fragment>
            );
          })}
        </div>
      </div>

      <p className="experience-footer reveal footer-reveal">
        Nagpur, India · 2023 - Present · Open to new collaborations
      </p>
    </section>
  );
}
